patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index fa05b8dd2242..73c2f4ecdd71 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7286,13 +7286,16 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   }

   // Return true if the loop contains any instructions that are not also part of
-  // the VPlan or are skipped for VPlan-based cost computations. This indicates
-  // that the VPlan contains extra simplifications.
-  return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
-    return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
+  // the VPlan. This indicates that the VPlan contains extra simplifications.
+  // We are more permissive here because instructions may be legitimately
+  // excluded from the VPlan due to optimizations that both cost models
+  // should agree upon, but the current cost model implementation may not
+  // perfectly track all such cases.
+  return any_of(TheLoop->blocks(), [&SeenInstrs](BasicBlock *BB) {
+    return any_of(*BB, [&SeenInstrs](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      return !SeenInstrs.contains(&I);
     });
   });
 }

