+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7288,11 +7288,16 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
-  return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
-    return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
+  return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx, TheLoop](BasicBlock *BB) {
+    return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      // Instructions that are loop-invariant can be legitimately hoisted out
+      // of the loop and don't need to appear in the VPlan.
+      if (!SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true) &&
+          !TheLoop->isLoopInvariant(&I))
+        return true;
+      return false;
     });
   });
 }
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index fa05b8dd2242..17a7a92cf1a3 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7288,11 +7288,32 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
-  return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
-    return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
+  // However, we need to be careful about instructions that are legitimately
+  // excluded from cost computation because they are dead or invariant.
+  // Check if the instruction would be considered dead in the vectorized version.
+  auto wouldBeTriviallyDeadInVectorizedLoop = [&CostCtx](Instruction &I) {
+    // If the instruction is already marked to be skipped in cost computation,
+    // it's legitimately excluded.
+    if (CostCtx.skipCostComputation(&I, true))
+      return true;
+    
+    // Check if all users of this instruction are also skipped in cost computation.
+    // This handles cases where an instruction feeds only into other instructions
+    // that are themselves skipped (e.g., dead computations).
+    return all_of(I.users(), [&CostCtx](User *U) {
+      if (auto *UI = dyn_cast<Instruction>(U))
+        return CostCtx.skipCostComputation(UI, true);
+      return false;
+    });
+  };
+  
+  return any_of(TheLoop->blocks(), [&SeenInstrs, &wouldBeTriviallyDeadInVectorizedLoop](BasicBlock *BB) {
+    return any_of(*BB, [&SeenInstrs, &wouldBeTriviallyDeadInVectorizedLoop](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      // If the instruction is not in the VPlan and wouldn't be trivially dead
+      // in the vectorized version, then the VPlan contains additional simplifications.
+      return !SeenInstrs.contains(&I) && !wouldBeTriviallyDeadInVectorizedLoop(I);
     });
   });
 }
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index fa05b8dd2242..a0176dcb028f 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7288,11 +7288,61 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
-  return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
-    return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
+  // However, we need to account for instructions that are legitimately excluded
+  // from the VPlan because they are dead or invariant. The CostCtx already
+  // contains information about which instructions should be skipped in cost
+  // computation, but we need to also consider instructions that feed only into
+  // skipped instructions.
+  
+  // Create a set of all instructions that are either explicitly skipped or
+  // feed only into skipped instructions (transitively).
+  SmallPtrSet<Instruction *, 32> AllSkippedInstrs;
+  
+  // First, add all instructions that are explicitly skipped.
+  for (BasicBlock *BB : TheLoop->blocks()) {
+    for (Instruction &I : *BB) {
+      if (CostCtx.skipCostComputation(&I, true))
+        AllSkippedInstrs.insert(&I);
+    }
+  }
+  
+  // Then, iteratively add instructions that feed only into already-skipped instructions.
+  bool Changed = true;
+  while (Changed) {
+    Changed = false;
+    for (BasicBlock *BB : TheLoop->blocks()) {
+      for (Instruction &I : *BB) {
+        if (AllSkippedInstrs.contains(&I) || isa<PHINode>(&I))
+          continue;
+        
+        // Check if all users of this instruction are in AllSkippedInstrs.
+        bool AllUsersSkipped = true;
+        for (User *U : I.users()) {
+          if (auto *UI = dyn_cast<Instruction>(U)) {
+            if (!AllSkippedInstrs.contains(UI)) {
+              AllUsersSkipped = false;
+              break;
+            }
+          } else {
+            // Non-instruction users (like constants) are not skipped.
+            AllUsersSkipped = false;
+            break;
+          }
+        }
+        
+        if (AllUsersSkipped) {
+          AllSkippedInstrs.insert(&I);
+          Changed = true;
+        }
+      }
+    }
+  }
+  
+  return any_of(TheLoop->blocks(), [&SeenInstrs, &AllSkippedInstrs](BasicBlock *BB) {
+    return any_of(*BB, [&SeenInstrs, &AllSkippedInstrs](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      return !SeenInstrs.contains(&I) && !AllSkippedInstrs.contains(&I);
     });
   });
 }
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index fa05b8dd2242..6eb54907cca3 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7288,11 +7288,27 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
-  return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
-    return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
+  // However, we need to account for the fact that some instructions may be
+  // legitimately excluded from the VPlan because they are loop-invariant and
+  // can be hoisted, or because they are dead in the vectorized version.
+  // The CostCtx already tracks instructions that should be skipped in cost
+  // computation via VecValuesToIgnore and ValuesToIgnore sets.
+  
+  // Additionally, check if the instruction is loop-invariant, as such
+  // instructions can be legitimately hoisted out of the loop and don't
+  // need to appear in the VPlan.
+  return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx, TheLoop](BasicBlock *BB) {
+    return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      if (!SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true)) {
+        // If the instruction is loop-invariant, it can be hoisted and doesn't
+        // need to be in the VPlan.
+        if (TheLoop->isLoopInvariant(&I))
+          return false;
+        return true;
+      }
+      return false;
     });
   });
 }
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index fa05b8dd2242..47495bf6c134 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7288,10 +7288,21 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
+  // However, we need to account for the fact that some instructions may be
+  // legitimately excluded from the VPlan because they are dead in the vectorized
+  // version. The CostCtx already tracks instructions that should be skipped in
+  // cost computation via VecValuesToIgnore and ValuesToIgnore sets.
+  // 
+  // Additionally, we need to consider that the precomputeCosts function may
+  // have added instructions to SkipCostComputation set that are not in
+  // VecValuesToIgnore or ValuesToIgnore, but are still legitimately excluded.
+  // So we should check the full skipCostComputation condition.
   return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
     return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
+      // If the instruction is not in the VPlan and is not skipped in cost
+      // computation, then the VPlan contains additional simplifications.
       return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
     });
   });
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index fa05b8dd2242..f08f1f73a509 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7288,11 +7288,23 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
+  // However, we must also account for instructions that are in CM.VecValuesToIgnore
+  // but may not be properly handled by skipCostComputation in all cases.
+  // Specifically, check if the instruction is in VecValuesToIgnore directly.
   return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
     return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
-      return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
+      if (SeenInstrs.contains(&I))
+        return false;
+      // Check if instruction is explicitly skipped in cost computation
+      if (CostCtx.skipCostComputation(&I, true))
+        return false;
+      // Additional check: if this is a vector context and the instruction
+      // is in VecValuesToIgnore, it should be considered as skipped
+      if (CostCtx.CM.VecValuesToIgnore.contains(&I))
+        return false;
+      return true;
     });
   });
 }
